const items = $input.all();

return items.map((item) => {
  const data = item.json;
  const url = data.soundcloud_link || '';
  const audit_flags = [];
  const audit_messages = [];

  if (!url.includes('soundcloud.com')) {
    audit_flags.push('NOT_SOUNDCLOUD_LINK');
    audit_messages.push('Your link must be a valid SoundCloud URL.');
  } else if (!url.includes('/s-')) {
    audit_flags.push('PUBLIC_LINK_WARNING');
    audit_messages.push(
      'Your SoundCloud link appears public. Private demo links (with /s-) are preferred for unreleased tracks.',
    );
  }

  const MIN_REFS = 3;
  const MAX_REFS = 5;
  const refCount = Array.isArray(data.reference_artists) ? data.reference_artists.length : 0;
  if (refCount < MIN_REFS) {
    audit_flags.push('MISSING_REFERENCE_ARTISTS');
    audit_messages.push(
      `Please provide at least ${MIN_REFS} reference artists (comma-separated).`,
    );
  } else if (refCount > MAX_REFS) {
    audit_flags.push('TOO_MANY_REFERENCE_ARTISTS');
    audit_messages.push(
      `Please provide no more than ${MAX_REFS} reference artists.`,
    );
  }

  const blocking = [
    'NOT_SOUNDCLOUD_LINK',
    'MISSING_REFERENCE_ARTISTS',
    'TOO_MANY_REFERENCE_ARTISTS',
  ];
  const is_valid_for_research = !audit_flags.some((flag) => blocking.includes(flag));

  return {
    json: {
      ...data,
      audit_flags,
      audit_messages,
      is_valid_for_research,
      phase: 'phase-01-preflight',
    },
  };
});
